/**
 * DeliveryNoteStats
 *
 * Resumen agregado de los albaranes de la empresa autenticada: total, importe acumulado, desglose por estado interno, pendientes de firma y convertidos a factura este mes. Devuelto por `GET /v1/delivery_notes/stats`.
 */
export type DeliveryNoteStats = {
    /**
     * Total number of recorded delivery notes.
     */
    total_count: number;
    /**
     * Importe acumulado de los albaranes (EUR).
     */
    total_amount: number;
    /**
     * Breakdown by internal delivery note state. The key is the internal state (`draft`, `delivered`, `invoiced`, `cancelled`); the value is an object with `status`, `count` and `total` (accumulated amount in EUR). States with no delivery notes do not appear.
     */
    by_status: {
        [key: string]: {
            /**
             * Internal state of the delivery note.
             */
            status: string;
            /**
             * Number of delivery notes in that state.
             */
            count: number;
            /**
             * Importe acumulado de los albaranes en ese estado (EUR).
             */
            total: number;
        };
    };
    /**
     * Delivered delivery notes (`delivered`) that do not yet have a recorded signature.
     */
    pending_signature: number;
    /**
     * Albaranes convertidos a factura (`invoiced`) durante el mes en curso.
     */
    converted_this_month: number;
};

