    /**
     * Indicates whether the public link is active.
     */
    public_link_active: boolean;
    /**
     * When the public link expires (ISO 8601), or `null`.
     */
    public_link_expires_at: string | null;
    /**
     * Number of reminders already sent for this invoice.
     */
    reminders_sent: number;
    /**
     * When the last reminder was sent (ISO 8601), or `null` if none has been sent.
     */
