/**
 * Tax
 *
 * A tax rate configuration. Catalog partially global (`is_system=true` for system taxes, without `company_id`) and partially custom per company.
 */
export type Tax = {
    id: string;
    object: 'tax';
    /**
     * Nombre legible del impuesto (ej. "IVA 21%").
     */
    name: string;
    /**
     * Short tax code (e.g. "IVA21").
     */
    code: string;
    /**
     * Tipo impositivo aplicado, ej. `21` para IVA 21%.
     */
    rate: number;
    /**
     * Tax category: `vat` (VAT), `retention` (IRPF withholding), `surcharge` (equivalence surcharge), `other`.
     */
    type: 'vat' | 'retention' | 'surcharge' | 'other';
    /**
     * Scope where it applies: `sales` (sales only), `purchases` (purchases only), `both` (both).
     */
    applies_to: 'sales' | 'purchases' | 'both';
    /**
     * ISO 3166-1 alpha-2 country code (e.g. `ES`).
     */
    country: string | null;
    /**
     * true si es el tax default para su `type` (independiente del map `default_for_documents`).
     */
    is_default: boolean;
    /**
     * Indicates whether the tax is enabled for use on new documents.
     */
    is_active: boolean;
    /**
     * true if the tax is from the global system catalog (not editable, without `company_id`).
     */
    is_system: boolean;
    /**
     * Free-text description of the tax.
     */
    description: string | null;
    /**
     * Map `DocumentType -> bool` indicating for which document types this tax is default. Replaces the 5 legacy booleans `is_default_invoice/quote/delivery_note/proforma/purchase_invoice`.
     */
    default_for_documents: {
        invoice: boolean;
        quote: boolean;
        delivery_note: boolean;
        proforma: boolean;
        purchase_invoice: boolean;
        recurring_invoice: boolean;
    };
    /**
     * Etiqueta del impuesto mostrada al cliente final en documentos (PDF, public link, email).
     */
    customer_visible_label: string | null;
    /**
     * AEAT-SII / VeriFactu key (closed catalog: S1..S3 subject, E1..E6 exempt, N1..N2 not subject).
     */
    external_reference: 'S1' | 'S2' | 'S3' | 'E1' | 'E2' | 'E3' | 'E4' | 'E5' | 'E6' | 'N1' | 'N2' | null;
    /**
     * Fecha de inicio de vigencia legal del tipo (BOE). Formato `YYYY-MM-DD`.
     */
    valid_from: string | null;
    /**
     * Fecha de fin de vigencia legal del tipo. Invariante: `valid_until >= valid_from` cuando ambos no-null.
     */
    valid_until: string | null;
    /**
     * Reverse charge (Art. 84.Uno.2º LIVA). Default `false`.
     */
    reverse_charge: boolean;
    /**
     * Zona AEAT a efectos fiscales: `peninsula` + Baleares, `canarias` (IGIC), `ceuta` (IPSI), `melilla` (IPSI).
     */
    country_aeat_zone: 'peninsula' | 'canarias' | 'ceuta' | 'melilla' | null;
    metadata: Metadata;
    created_at: string | null;
    updated_at: string | null;
};

/**
 * TaxCalculation
 *
 * Resultado de aplicar un tax a un importe base. Devuelto por `POST /v1/taxes/calculate`.
 */
export type TaxCalculation = {
    /**
     * Importe base sobre el que se aplica el tax (EUR).
     */
    base: number;
    /**
     * Tipo impositivo aplicado, ej. `21` para IVA 21%.
     */
    tax_rate: number;
    /**
     * Cuota del impuesto (base × tax_rate / 100).
     */
    tax_amount: number;
    /**
     * Importe total resultante (base + tax_amount).
     */
    total_amount: number;
    tax: Tax;
};

/**
 * TaxDefaultsForDocuments
 *
 * Defaults grouped by tax category for a given document type. Each key contains the (possibly empty) list of taxes marked as default for that `docType` within its `type`.
 */
export type TaxDefaultsForDocuments = {
    /**
     * Taxes con `type=vat` que son default para el docType consultado.
     */
    vat: Array<Tax>;
    retention: Array<Tax>;
    surcharge: Array<Tax>;
    other: Array<Tax>;
};

/**
 * TaxRateRef
 */
export type TaxRateRef = {
    id: string | null;
    rate: number | null;
};

/**
 * TaxReport
 *
 * A generated Spanish tax declaration (Modelo 303 quarterly VAT, or Modelo 347 yearly informational). Downloadable via `GET /v1/tax_reports/{uuid}/download`.
 */
export type TaxReport = {
    /**
     * UUID (v7) opaco del informe generado.
     */
    id: string;
    object: 'tax_report';
    /**
     * Declaration type.
     */
    type: 'modelo_303' | 'modelo_347';
    /**
     * Fiscal year covered by the declaration (backward compat, also available in `period.year`).
     */
    period_year: number;
    /**
     * Quarter (1-4) for Modelo 303; null for Modelo 347 (yearly). Backward compat, also available in `period.quarter`.
     */
    period_quarter: number | null;
    /**
     * Fiscal period covered by the declaration (nested form).
     */
    period: {
        /**
         * Fiscal year.
         */
        year: number;
        /**
         * Trimestre (1-4) o `null` para declaraciones anuales (347).
         */
        quarter: number | null;
        /**
         * Human-readable period label (e.g. `2026 Q1` or `2026`).
         */
        label: string;
    };
    /**
     * Output format. `txt_aeat` is the official format accepted by the AEAT submission portal.
     */
    format: 'txt_aeat' | 'pdf' | 'excel';
    /**
     * SHA-256 of the generated file (audit trail).
     */
    hash: string;
    size_bytes: number;
    generated_at: string;
    /**
     * UUID (v7) of the user who generated the declaration (audit trail).
     */
    generated_by_id: string;
    /**
     * URL relativa de descarga del recurso generado (`/v1/tax_reports/{uuid}/download`).
     */
    download_url: string;
    /**
     * Non-blocking warnings emitted during generation (e.g. invoices with incomplete data).
     */
    warnings: Array<string>;
};

/**
 * TaxReportActivity
 *
 * An event in the activity timeline of a tax report generation (creation, download, etc.). The `metadata` is sanitized (internal PKs removed) before being exposed.
 */
export type TaxReportActivity = {
    object: 'activity';
    /**
     * Tipo de evento de dominio (p. ej. `tax_report.generated`).
     */
    event_type: string;
    /**
     * Human-readable description of the event in Spanish.
     */
    description: string;
    /**
     * Metadatos del evento. Los identificadores internos (PKs) se eliminan; los `*_uuid` se conservan.
     */
    metadata: {
        [key: string]: unknown;
    };
    /**
     * Actor that originated the event. `null` when the event is system-generated or there is no associated user.
     */
    performed_by: {
        /**
         * Type of actor that originated the event.
         */
        type: 'user';
        /**
         * UUID (v7) of the user who performed the action.
         */
        id: string;
        /**
         * Nombre del usuario en el momento del evento.
         */
        name: string | null;
    } | null;
    /**
     * When the event occurred (ISO 8601).
     */
    created_at: string;
};

/**
 * TaxReportPreview
 *
 * Preview (dry-run computation, without persisting any file) of a Modelo 303/347 for a period. Lets the integrator validate the amounts before generating the final report. Amounts are expressed in euro cents (integers).
 */
export type TaxReportPreview = {
    object: 'tax_report_preview';
    /**
     * Type of previewed report.
     */
    type: 'modelo_303' | 'modelo_347';
    /**
     * Previewed fiscal period.
     */
    period: {
        /**
         * Fiscal year.
         */
        year: number;
        /**
         * Trimestre (1-4) o `null` para declaraciones anuales (347).
         */
        quarter: number | null;
        /**
         * Human-readable period label (e.g. `2026 Q1`).
         */
        label: string;
    };
    /**
     * Breakdown by VAT rate (Modelo 303 only). Map indexed by tax rate → `{base, cuota}` in cents. Empty for Modelo 347.
     */
    breakdown_303: {
        [key: string]: {
            /**
             * Accumulated taxable base for that VAT rate, in cents.
             */
            base?: number;
            /**
             * Accumulated VAT amount for that rate, in cents.
             */
            cuota?: number;
        };
    };
    /**
     * Aggregated totals of the declaration (amounts in cents).
     */
    totals: {
        [key: string]: number;
    };
    /**
     * Operations with clients that exceed the Modelo 347 threshold (Modelo 347 only). Empty for Modelo 303.
     */
    clients_347: Array<{
        /**
         * NIF/CIF del cliente.
         */
        taxId?: string | null;
        /**
         * Name or legal/business name of the client.
         */
        partyName?: string | null;
        /**
         * Total annual amount of operations, in cents.
         */
        base?: number;
        /**
         * Amount per quarter (quarter key → amount in cents).
         */
        quarters?: {
            [key: string]: number;
        };
    }>;
    /**
     * Operations with suppliers that exceed the Modelo 347 threshold (Modelo 347 only). Empty for Modelo 303.
     */
    suppliers_347: Array<{
        /**
         * NIF/CIF del proveedor.
         */
        taxId?: string | null;
        /**
         * Name or legal/business name of the supplier.
         */
        partyName?: string | null;
        /**
         * Total annual amount of operations, in cents.
         */
        base?: number;
        /**
         * Amount per quarter (quarter key → amount in cents).
         */
        quarters?: {
            [key: string]: number;
        };
    }>;
    /**
     * Number of issued invoices considered in the period.
     */
    invoice_count: number;
    /**
     * Number of purchase invoices considered in the period.
     */
    purchase_invoice_count: number;
    /**
     * Non-blocking warnings detected during the computation (e.g. invoices with incomplete data).
     */
    warnings: Array<string>;
};

/**
 * TaxReportStats
 *
 * Aggregated summary of the history of tax reports generated by the authenticated company: totals by type, by format, accumulated size and current fiscal period. Returned by `GET /v1/tax_reports/stats`.
 */
export type TaxReportStats = {
    object: 'tax_report_stats';
    /**
     * Total number of generated reports.
     */
    total_reports: number;
    /**
     * Recuento de declaraciones por tipo.
     */
    by_type: {
        /**
         * Declaraciones Modelo 303 generadas.
         */
        modelo_303: number;
        /**
         * Declaraciones Modelo 347 generadas.
         */
        modelo_347: number;
    };
    /**
     * Recuento de declaraciones por formato de salida.
     */
    by_format: {
        /**
         * Ficheros en formato oficial AEAT.
         */
        txt_aeat: number;
        /**
         * Ficheros PDF.
         */
        pdf: number;
        /**
         * Ficheros Excel.
         */
        excel: number;
    };
    /**
     * Accumulated size (bytes) of all generated files.
     */
    total_size_bytes: number;
    /**
     * Trimestre fiscal en curso (UTC).
     */
    current_quarter: {
        year: number;
        quarter: number;
    };
    /**
     * Current fiscal year (UTC).
     */
    current_year: number;
};

/**
 * TaxStats
 *
 * Aggregated KPIs over the company tax catalog (includes global system taxes). Breakdown por `type` y por `external_reference` AEAT.
 */
export type TaxStats = {
    object: 'tax_stats';
    /**
     * Total de taxes visibles para la empresa (system + custom).
     */
    total: number;
    /**
     * Taxes con `is_active=true`.
     */
    active: number;
    /**
     * Taxes con `is_active=false`.
     */
    inactive: number;
    /**
     * Taxes from the global system catalog (`is_system=true`).
     */
    system_count: number;
    /**
     * Company-specific taxes (`is_system=false`).
     */
    custom_count: number;
    /**
     * Conteo de taxes por `type`.
     */
    by_type: {
        vat: number;
        retention: number;
        surcharge: number;
        other: number;
    };
    /**
     * Tax count by AEAT `external_reference`. The `"(null)"` key groups taxes without an assigned AEAT code.
     */
    by_aeat_code: {
        [key: string]: number;
    };
};

/**
 * TaxTotals
 *
 * Aggregated totals of a set of lines. Returned by `POST /v1/taxes/calculate-totals`. Total formula: `subtotal + total_vat + total_surcharge − total_retention`.
 */
export type TaxTotals = {
    /**
     * Sum of the taxable bases of all lines (EUR).
     */
    subtotal: number;
    /**
     * Sum of the VAT of all lines.
     */
    total_vat: number;
    /**
     * Sum of the equivalence surcharge of all lines.
     */
    total_surcharge: number;
    /**
     * Sum of the withholding (IRPF) of all lines.
     */
    total_retention: number;
    /**
     * Total general.
     */
    total: number;
    /**
     * Calculated breakdown for each received line, in the same order.
     */
    lines: Array<TaxTotalsLine>;
};

/**
 * TaxTotalsLine
 *
 * Calculated breakdown of a single line within `POST /v1/taxes/calculate-totals`.
 */
export type TaxTotalsLine = {
    /**
     * Taxable base of the line (quantity × price − discount).
     */
    subtotal: number;
    /**
     * VAT amount of the line.
     */
    vat_amount: number;
    /**
     * Equivalence surcharge amount of the line.
     */
    surcharge_amount: number;
    /**
     * Withholding (IRPF) amount of the line.
     */
    retention_amount: number;
    /**
     * Total of the line (subtotal + vat + surcharge − retention).
     */
    total: number;
};

/**
 * TaxUsage
 *
 * Desglose del uso de un tax across bounded contexts. Permite decidir si es seguro borrar o desactivar un tax (`in_use=false` ⇒ delete seguro).
 */
export type TaxUsage = {
    object: 'tax_usage';
    /**
     * UUID (v7) del tax consultado.
     */
    taxes_id: string;
    /**
     * true si `total_count > 0`.
     */
    in_use: boolean;
    /**
     * Suma agregada de las 6 keys de `used_by`.
     */
    total_count: number;
    /**
     * Count by consumer BC. Excludes `purchase_invoice_lines` (no FK) and `recurring_invoices` (JSON lines).
     */
    used_by: {
        /**
         * `products.tax_id` referencias.
         */
        products: number;
        /**
         * `suppliers.default_tax_id` referencias.
         */
        suppliers: number;
        /**
         * `invoice_lines.{vat_id,retention_id,surcharge_id,tax_id}` referencias.
         */
        invoice_lines: number;
        quote_lines: number;
        proforma_lines: number;
        delivery_note_lines: number;
    };
};

