/**
 * VeriFactuActivity
 *
 * An event in the activity timeline of a VeriFactu record (creation, transmission attempts, AEAT acceptance/rejection).
 */
export type VeriFactuActivity = {
    object: 'verifactu_activity';
    /**
     * Tipo de evento de dominio (p. ej. `verifactu.record_created`, `verifactu.transmission_accepted`).
     */
    event_type: string;
    /**
     * Human-readable description of the event in Spanish.
     */
    description: string;
    /**
     * Metadatos del evento. Los identificadores internos (PKs), `huella` y secretos de certificado se eliminan; los `*_uuid` se conservan.
     */
    metadata: {
        [key: string]: unknown;
    };
    /**
     * Actor that originated the event. `null` when the event is system-generated or there is no associated user.
     */
    performed_by: {
        /**
         * Type of actor that originated the event.
         */
        type: 'user';
        /**
         * UUID (v7) of the user who performed the action.
         */
        id: string;
        /**
         * Nombre del usuario en el momento del evento.
         */
        name: string | null;
    } | null;
    /**
     * When the event occurred (ISO 8601).
     */
    created_at: string;
};

/**
 * VeriFactuConfig
 *
 * VeriFactu configuration of your company (mode, environment, enrollment). Returned by `GET /v1/verifactu/config` and `PUT /v1/verifactu/settings`. The certificate password is never exposed.
 */
export type VeriFactuConfig = {
    object: 'verifactu_config';
    /**
     * Indicates whether VeriFactu is enabled for the company.
     */
    enabled: boolean;
    /**
     * VeriFactu operation mode.
     */
    mode: string;
    /**
     * Indicates whether transmissions to AEAT are sent automatically.
     */
    auto_transmit: boolean;
    /**
     * Entorno AEAT (`sandbox` / `production`).
     */
    environment: string;
    /**
     * Notification emails for VeriFactu events.
     */
    notification_emails: Array<string>;
    /**
     * Date until which the mode change is locked (BR-VFC-001), or `null` if not locked.
     */
    is_locked_until: string | null;
    /**
     * Indica si hay un certificado activo configurado.
     */
    has_active_certificate: boolean;
    /**
     * UUID (v7) del certificado activo, o `null` si no hay ninguno.
     */
    active_certificate_id: string | null;
    updated_at: string | null;
};

/**
 * VeriFactuEvent
 *
 * A VeriFactu SIF event (Art. 8.1.b): a transmission/retry/AEAT-response entry of the system. The hash chain is never exposed here.
 */
export type VeriFactuEvent = {
    /**
     * UUID (v7) del evento.
     */
    id: string;
    object: 'verifactu_event';
    /**
     * Tipo de evento del SIF.
     */
    event_type: string;
    /**
     * Non-PII descriptive data of the event (label, description, CSV, error code/message). Empty object `{}` when there is no data. Sanitized via MetadataSanitizer.
     */
    event_data: {
        [key: string]: unknown;
    };
    /**
     * Estado AEAT del evento.
     */
    status: string;
    /**
     * When the event was generated.
     */
    occurred_at: string;
    created_at: string;
    /**
     * Number of transmission attempts made.
     */
    retry_count: number;
    /**
     * Maximum number of retries configured.
     */
    max_retries: number;
};

/**
 * VeriFactuEventSummary
 *
 * Resumen agregado de los eventos del SIF de la empresa: total y desglose por tipo y por estado. Devuelto por `GET /v1/verifactu/events/summary`.
 */
export type VeriFactuEventSummary = {
    object: 'verifactu_event_summary';
    /**
     * Total de eventos registrados.
     */
    total_events: number;
    /**
     * Recuento de eventos por tipo.
     */
    events_by_type: {
        [key: string]: number;
    };
    /**
     * Recuento de eventos por estado AEAT.
     */
    events_by_status: {
        [key: string]: number;
    };
    /**
     * Date of the last event, or `null` if there is none.
     */
    last_event_at: string | null;
};

/**
 * VeriFactuRecord
 *
 * A VeriFactu (Spanish AEAT SIF) record (alta/anulación) associated with an invoice. Includes the hash chain (`huella`), AEAT CSV and transmission status for reconciliation.
 */
export type VeriFactuRecord = {
    /**
     * UUID (v7) del registro VeriFactu.
     */
    id: string;
    object: 'verifactu_record';
    /**
     * Tipo de registro (`alta` / `anulacion`).
     */
    type: string;
    /**
     * Tipo de factura AEAT (F1, F2, F3, R1-R5, …).
     */
    invoice_type: string;
    /**
     * Number of the associated invoice.
     */
    invoice_number: string;
    /**
     * Fecha del registro.
     */
    date: string;
    /**
     * Importe total de la factura asociada.
     */
    amount: number;
    /**
     * Transmission status (pending, submitted, accepted, rejected, error).
     */
    status: string;
    /**
     * Huella SHA-256 encadenada del registro (fingerprint VeriFactu).
     */
    huella: string;
    /**
     * Submission identifier assigned by AEAT (column `aeat_submission_id`). `null` until AEAT returns it. Never the internal PK of the record.
     */
    aeat_submission_id: string | null;
    /**
     * Secure Verification Code (Código Seguro de Verificación) returned by AEAT on acceptance. `null` until AEAT assigns it.
     */
    aeat_csv: string | null;
    /**
     * Entorno AEAT (`sandbox` / `production`).
     */
    environment: string;
    /**
     * ISO 8601 date of the last transmission that reached AEAT. `null` in PENDING/REJECTED/ERROR states.
     */
    transmitted_at: string | null;
    /**
     * Indica si la factura es simplificada (F2).
     */
    is_simplificada: boolean;
    /**
     * Indica si sustituye a una o varias facturas simplificadas (F3).
     */
    is_substitute_for_simplified: boolean;
    created_at: string;
};

/**
 * VeriFactuStats
 *
 * Resumen agregado de los registros VeriFactu de la empresa autenticada: conteos por estado y desglose por tipo. Devuelto por `GET /v1/verifactu/stats`.
 */
export type VeriFactuStats = {
    object: 'verifactu_stats';
    /**
     * Total de registros VeriFactu.
     */
    total_records: number;
    /**
     * Records pending transmission.
     */
    pending: number;
    /**
     * Records submitted to AEAT (without a final response yet).
     */
    submitted: number;
    /**
     * Registros aceptados por AEAT.
     */
    accepted: number;
    /**
     * Registros rechazados por AEAT.
     */
    rejected: number;
    /**
     * Registros en estado de error.
     */
    error: number;
    /**
     * Recuento por tipo de registro (alta/anulacion).
     */
    by_record_type: {
        [key: string]: number;
    };
    /**
     * Recuento por tipo de factura AEAT (F1, F2, F3, …).
     */
    by_invoice_type: {
        [key: string]: number;
    };
    /**
     * Date of the last transmission to AEAT, or `null` if there is none.
     */
    last_transmission_at: string | null;
};

